def thread_num():
    while True:
        try:
            num = int(input('请输入线程数（1-1000）：'))
            if num <= 0:
                print('线程数需大于0')
                continue
            elif num > 1000:
                print('最大线程数不可超过1000')
                continue
            return num
        except ValueError:
            print('请输入有效的数字')


